  ('lei', '16.383', 2025, '2025-11-17', 'Reajusta a remuneração dos guarda-vidas civis de que trata a Lei n.º 15.897, de 24 de novembro de 2022, que autoriza o Poder Executivo a contratar guarda-vidas civis, em caráter temporário.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=1347880', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=76620&Texto=&Origem=1', 'DOE-RS:1347880', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"76620","alrs_tipo_norma":"20","alrs_numero_raw":"16383","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=76620&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":1347880,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/1347880","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2025-11-18&pg=6","doe_publicacao_data":"2025-11-18","doe_publicacao_pagina":"6","proposicao":"PL 381/2025","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/381/2025"}'),
