  ('lei', '16.349', 2025, '2025-09-24', 'Altera a Lei nº 15.934, de 1º de janeiro de 2023, que dispõe sobre a estrutura administrativa e diretrizes do Poder Executivo do Estado do Rio Grande do Sul e dá outras providências, e a Lei nº 15.935, de 1º de janeiro de 2023, que institui o Novo Quadro Geral dos Cargos em Comissão e Funções Gratificadas do Poder Executivo, regulamenta a gratificação pelo exercício de direção e de vice-direção de Escola da Rede Pública Estadual de Ensino, fixa a remuneração mensal dos dirigentes de autarquias, fundações autárquicas, órgãos e entidades especiais, dispõe sobre a equipe de transição do candidato eleito para o cargo de Governador do Estado, extingue cargos, funções e gratificações, e dá outras providências.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=1325575', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=76438&Texto=&Origem=1', 'DOE-RS:1325575', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"76438","alrs_tipo_norma":"20","alrs_numero_raw":"16349","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=76438&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":1325575,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/1325575","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2025-09-24&pg=438&ed=3","doe_publicacao_data":"2025-09-24","doe_publicacao_pagina":"438","proposicao":"PL 276/2025","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/276/2025"}'),
