  ('lei', '16.247', 2024, '2024-12-25', 'Dispõe sobre a criação de cargos de servidores constantes do Quadro de Pessoal dos Serviços Auxiliares e do Quadro de Cargos em Comissão e Funções Gratificadas da Defensoria Pública do Estado, e dá outras providências.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=1180983', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75803&Texto=&Origem=1', 'DOE-RS:1180983', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"75803","alrs_tipo_norma":"20","alrs_numero_raw":"16247","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75803&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":1180983,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/1180983","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2024-12-27&pg=19","doe_publicacao_data":"2024-12-27","doe_publicacao_pagina":"19","proposicao":"PL 291/2024","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/291/2024"}'),
  ('lei', '16.248', 2024, '2024-12-25', 'Dispõe sobre o subsídio mensal dos Procuradores do Estado do Rio Grande do Sul.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=1180984', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75804&Texto=&Origem=1', 'DOE-RS:1180984', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"75804","alrs_tipo_norma":"20","alrs_numero_raw":"16248","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75804&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":1180984,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/1180984","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2024-12-27&pg=20","doe_publicacao_data":"2024-12-27","doe_publicacao_pagina":"20","proposicao":"PL 369/2024","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/369/2024"}'),
  ('lei', '16.249', 2024, '2024-12-25', 'Altera a Lei nº 16.165, de 31 de julho de 2024, que reorganiza os quadros, as carreiras e reajusta as remunerações dos servidores públicos do Poder Executivo do Estado do Rio Grande do Sul, institui o Quadro das Carreiras Transversais de Nível Superior do Poder Executivo do Estado do Rio Grande do Sul e cria as carreiras de Analista de Políticas Públicas e Gestão Governamental, de Especialista em Infraestrutura, de Especialista em Tecnologia da Informação e Comunicação, de Fiscal, de Pesquisador e de Médico; institui o Quadro das Carreiras Transversais de Nível Técnico e de Nível Médio do Poder Executivo do Estado do Rio Grande do Sul e cria as carreiras de Técnico de Políticas Públicas e Gestão Governamental, de Assistente de Políticas Públicas e Gestão Governamental e de Guarda Parque; institui o Quadro das Carreiras da Saúde e cria as carreiras de Analista em Saúde e de Técnico em Saúde; cria a Carreira de Analista de Planejamento e Orçamento; institui o Quadro de Apoio Escolar e cria as carreiras de Técnico Educacional, de Assistente Educacional e de Auxiliar Educacional; cria as Carreiras de Analista e de Técnico no Quadro dos Serviços Auxiliares da Procuradoria-Geral do Estado e dá outras providências; e a Lei nº 15.790, de 29 de dezembro de 2021, que extingue o Quadro de Pessoal da Superintendência do Porto do Rio Grande - SUPRG - de que trata a Lei nº 13.602, de 3 de janeiro de 2011, e dá outras providências.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=1180988', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75805&Texto=&Origem=1', 'DOE-RS:1180988', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"75805","alrs_tipo_norma":"20","alrs_numero_raw":"16249","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75805&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":1180988,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/1180988","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2024-12-27&pg=20","doe_publicacao_data":"2024-12-27","doe_publicacao_pagina":"20","proposicao":"PL 370/2024","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/370/2024"}'),
