  ('lei', '16.233', 2024, '2024-12-16', 'Altera a Lei nº 15.516, de 8 de setembro de 2020, que estabelece o Plano de Cargos, Carreiras e Salários - PCCS - no Quadro de Pessoal de Provimento Efetivo dos Serviços Auxiliares do Ministério Público do Estado do Rio Grande do Sul; a Lei nº 11.332, de 7 de junho de 1999, que dispõe sobre as atribuições dos cargos em comissão e funções gratificadas da Procuradoria-Geral de Justiça; e a Lei nº 9.504, de 15 de janeiro de 1992, que dispõe sobre o Quadro de Cargos em Comissão e Funções Gratificadas da Procuradoria-Geral de Justiça, e dá outras providências.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=1177680', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75767&Texto=&Origem=1', 'DOE-RS:1177680', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"75767","alrs_tipo_norma":"20","alrs_numero_raw":"16233","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75767&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":1177680,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/1177680","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2024-12-17&pg=34","doe_publicacao_data":"2024-12-17","doe_publicacao_pagina":"34","proposicao":"PL 211/2024","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/211/2024"}'),
