  ('lei', '16.109', 2024, '2024-04-09', 'Altera a Lei nº 6.537, de 27 de fevereiro de 1973, que dispõe sobre o procedimento tributário administrativo e dá outras providências; altera a Lei nº 8.820, de 27 de janeiro de 1989, que institui o Imposto sobre Operações Relativas à Circulação de Mercadorias e sobre Prestações de Serviços de Transporte Interestadual e Intermunicipal e de Comunicação - ICMS - e dá outras providências; e revoga a Lei nº 15.854, de 21 de junho de 2022, que altera a Lei nº 15.766, de 20 de dezembro de 2021, que dispõe sobre a parcela do produto da arrecadação do Imposto sobre Operações Relativas à Circulação de Mercadorias e sobre Prestações de Serviços de Transporte Interestadual e Intermunicipal e de Comunicação - ICMS - pertencente aos municípios.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=985095', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75198&Texto=&Origem=1', 'DOE-RS:985095', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"75198","alrs_tipo_norma":"20","alrs_numero_raw":"16109","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=75198&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":985095,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/985095","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2024-04-10&pg=6","doe_publicacao_data":"2024-04-10","doe_publicacao_pagina":"6","proposicao":"PL 22/2024","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/22/2024"}'),
