  ('lei', '16.051', 2023, '2023-12-05', 'Altera a Lei nº 15.934, de 1º de janeiro de 2023, que dispõe sobre a estrutura administrativa e diretrizes do Poder Executivo do Estado do Rio Grande do Sul e dá outras providências; a Lei nº 13.888, de 30 de dezembro de 2011, que institui Sistema de Gestão de Ética, Controle Público e Transparência do Poder Executivo Estadual e dá outras providências; a Lei nº 14.485, de 30 de janeiro de 2014, que institui o Sistema Estadual de Ouvidoria do Poder Executivo Estadual - SEO/RS - e revoga os arts. 8º e 9º da Lei nº 13.888, de 30 de dezembro de 2011; a Lei nº 14.040, de 6 de julho de 2012, que institui o Fundo Estadual de Apoio à Inclusão Social e Produtiva - FEAISP; e a Lei nº 11.766, de 5 de abril de 2002, que extingue, cria e reduz funções gratificadas, regulamentando a Lei Complementar nº 11.742, de 17 de janeiro de 2002, autoriza conversão de vencimentos e dá outras providências.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=932908', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=74883&Texto=&Origem=1', 'DOE-RS:932908', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"74883","alrs_tipo_norma":"20","alrs_numero_raw":"16051","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=74883&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":932908,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/932908","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2023-12-06&pg=5","doe_publicacao_data":"2023-12-06","doe_publicacao_pagina":"5","proposicao