  ('lei', '15.980', 2023, '2023-07-17', 'Fixa o valor da indenização mensal destinada à manutenção dos instrumentos musicais, bem como o vestuário exigido para as apresentações da Orquestra, a que se refere o art. 4º da Lei nº 12.404, de 20 de dezembro de 2005, que cria o Quadro de Professores de Orquestra Sinfônica na Fundação Orquestra Sinfônica de Porto Alegre - FOSPA -, e dá outras providências.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=881286', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=73540&Texto=&Origem=1', 'DOE-RS:881286', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"73540","alrs_tipo_norma":"20","alrs_numero_raw":"15980","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=73540&Texto=&Origem=1","alrs_coverage_slice":"01/01/2023-27/04/2026","doe_materia_id":881286,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/881286","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2023-07-18&pg=5","doe_publicacao_data":"2023-07-18","doe_publicacao_pagina":"5","proposicao":"PL 262/2022","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/262/2022"}'),
