  ('lei', '15.795', 2022, '2022-01-24', 'Cria a Unidade Regional de Saneamento Básico 1 - URSB 1 - e a Unidade Regional de Saneamento Básico 2 - URSB 2, com fundamento no disposto na alínea "b" do inciso VI do art. 3º da Lei Federal nº 11.445, de 5 de janeiro de 2007, com a redação dada pela Lei Federal nº 14.026, de 15 de julho de 2020, com o objetivo de propiciar viabilidade técnica e econômico-financeira ao bloco e garantir, mediante a prestação regionalizada, a universalização dos serviços públicos de abastecimento de água potável e de esgotamento sanitário, e altera a Lei nº 12.037, de 19 de dezembro de 2003, que dispõe sobre a Política Estadual de Saneamento e dá outras providências.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=669214', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=72403&Texto=&Origem=1', 'DOE-RS:669214', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"72403","alrs_tipo_norma":"20","alrs_numero_raw":"15795","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=72403&Texto=&Origem=1","alrs_coverage_slice":"01/01/2019-31/12/2022","doe_materia_id":669214,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/669214","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2022-01-25&pg=5","doe_publicacao_data":"2022-01-25","doe_publicacao_pagina":"5","proposicao":"PL 422/2021","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/422/2021"}'),
