  ('lei', '15.664', 2021, '2021-07-13', 'Declara o Município de São Luiz Gonzaga Capital Gaúcha do Arroz Carreteiro e inclui a Festa do Arroz Carreteiro no Calendário Oficial de Eventos do Estado do Rio Grande do Sul.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=569928', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=71861&Texto=&Origem=1', 'DOE-RS:569928', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"71861","alrs_tipo_norma":"20","alrs_numero_raw":"15664","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=71861&Texto=&Origem=1","alrs_coverage_slice":"01/01/2019-31/12/2022","doe_materia_id":569928,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/569928","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2021-07-14&pg=7","doe_publicacao_data":"2021-07-14","doe_publicacao_pagina":"7","proposicao":"PL 472/2019","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/472/2019"}'),
