  ('lei_complementar', '15.559', 2020, '2020-12-09', 'Autoriza os órgãos e entidades integrantes da Administração Pública Direta e Indireta de qualquer dos Poderes do Estado, bem como o Ministério Público Estadual, o Tribunal de Contas do Estado e a Defensoria Pública do Estado, a realizar o desconto na remuneração, proventos e pensões de seus membros ou servidores, ativos ou inativos, do valor referente ao auxílio emergencial recebido em desconformidade com a Lei Federal n.º 13.982, de 2 de abril de 2020.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=496128', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=71339&Texto=&Origem=1', 'DOE-RS:496128', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"71339","alrs_tipo_norma":"2","alrs_numero_raw":"15559","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=71339&Texto=&Origem=1","alrs_coverage_slice":"01/01/2019-31/12/2022","doe_materia_id":496128,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/496128","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2020-12-09&pg=256","doe_publicacao_data":"2020-12-09","doe_publicacao_pagina":"256","proposicao":"PLC 224/2020","proposicao_url":"https://www.al.rs.gov.br/proposicao/PLC/224/2020"}'),
