  ('lei', '15.451', 2020, '2020-02-17', 'Altera a Lei nº 6.672, de 22 de abril de 1974, que institui o Estatuto e Plano de Carreira do Magistério Público do Rio Grande do Sul.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=387259', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=66087&Texto=&Origem=1', 'DOE-RS:387259', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"66087","alrs_tipo_norma":"20","alrs_numero_raw":"15451","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=66087&Texto=&Origem=1","alrs_coverage_slice":"01/01/2019-31/12/2022","doe_materia_id":387259,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/387259","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2020-02-18&pg=17","doe_publicacao_data":"2020-02-18","doe_publicacao_pagina":"17","proposicao":"PL 3/2020","proposicao_url":"https://www.al.rs.gov.br/proposicao/PL/3/2020"}'),
  ('lei_complementar', '15.450', 2020, '2020-02-17', 'Altera a Lei Complementar n.º 10.098, de 3 de fevereiro de 1994, que dispõe sobre o estatuto e regime jurídico único dos servidores públicos civis do Estado do Rio Grande do Sul, a Lei n.º 10.002, de 6 de dezembro de 1993, que autoriza o Poder Executivo a instituir um sistema de vale-refeição no âmbito da Administração Direta e das Autarquias, e a Lei Complementar n.º 15.142, de 5 de abril de 2018, que dispõe sobre o Regime Próprio de Previdência Social do Estado do Rio Grande do Sul - RPPS/RS - e dá outras providências.', 'EDUARDO LEITE', 'https://www.diariooficial.rs.gov.br/materia?id=387258', 'Diario Oficial do Estado do Rio Grande do Sul - Atos do Governador', 'https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=66086&Texto=&Origem=1', 'DOE-RS:387258', '{"source":"DOE-RS/ALRS","data_real":true,"fluxo":"5B","coverage_id":"eduardo-leite-rs-completo-leis-ordinarias-complementares-2019-2022-2023-2026-04-27","coverage_label":"Leis ordinarias e complementares do Rio Grande do Sul assinadas por Eduardo Leite como governador, indexadas na ALRS e verificadas no DOE-RS ate 27/04/2026","alrs_id_norma":"66086","alrs_tipo_norma":"2","alrs_numero_raw":"15450","alrs_detail_url":"https://www.al.rs.gov.br/legis/M010/M0100018.asp?Hid_IdNorma=66086&Texto=&Origem=1","alrs_coverage_slice":"01/01/2019-31/12/2022","doe_materia_id":387258,"doe_api_url":"https://secweb.procergs.com.br/doe/rest/public/materias/387258","doe_diario_url":"https://www.diariooficial.rs.gov.br/diario?td=DOE&dt=2020-02-18&pg=10","doe_publicacao_data":"2020-02-18","doe_publicacao_pagina":"10","proposicao":"PLC 2/2020","proposicao_url":"https://www.al.rs.gov.br/proposicao/PLC/2/2020"}'),
