UPDATE legislacao_mandato_executivo lme
SET
  ementa = s.ementa,
  signatario = s.signatario,
  autoridade_papel = 'titular',
  fonte_primaria_url = s.fonte_primaria_url,
  fonte_primaria_titulo = s.fonte_primaria_titulo,
  fonte_tramitacao_url = s.fonte_tramitacao_url,
  identificador_fonte = s.identificador_fonte,
  metadata = s.metadata::jsonb
FROM _seed_eduardo_leite_rs_legislacao_completa s
JOIN candidatos c ON c.slug = 'eduardo-leite'
WHERE lme.candidato_id = c.id
  AND lme.tipo_relacao = 'lei_sancionada'
  AND lme.tipo_norma = s.tipo_norma
  AND lme.numero = s.numero
  AND lme.ano = s.ano
  AND lme.data_norma = s.data_norma::date;

INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  c.id,
  (
    SELECT hp.id
    FROM historico_politico hp
    WHERE hp.candidato_id = c.id
      AND (
        hp.cargo ILIKE '%Governador%'
        OR hp.cargo_canonico = 'Governador'
      )
      AND hp.periodo_inicio <= s.ano
      AND (hp.periodo_fim IS NULL OR hp.periodo_fim >= s.ano)
    ORDER BY hp.periodo_inicio DESC
    LIMIT 1
  ),
  'lei_sancionada',
  'estadual',
  'RS',
  s.tipo_norma,
  s.numero,
  s.ano,
  s.data_norma::date,
  s.ementa,
  s.signatario,
  'titular',
  s.fonte_primaria_url,
  s.fonte_primaria_titulo,
  s.fonte_tramitacao_url,
  s.identificador_fonte,
  s.metadata::jsonb
FROM _seed_eduardo_leite_rs_legislacao_completa s
JOIN candidatos c ON c.slug = 'eduardo-leite'
WHERE NOT EXISTS (
  SELECT 1
  FROM legislacao_mandato_executivo lme
  WHERE lme.candidato_id = c.id
    AND lme.tipo_relacao = 'lei_sancionada'
    AND lme.tipo_norma = s.tipo_norma
    AND lme.numero = s.numero
    AND lme.ano = s.ano
    AND lme.data_norma = s.data_norma::date
);

DROP TABLE _seed_eduardo_leite_rs_legislacao_completa;
